-- ============================================================
-- AVIA Homes — Catalogue Tables (Colours, Specs, Schemes, Ranges)
-- Run this in Supabase SQL Editor AFTER supabase_schema.sql
-- and supabase_content_tables.sql
-- ============================================================

-- 1. Colour Categories
CREATE TABLE IF NOT EXISTS colour_categories (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    icon TEXT NOT NULL,
    section TEXT NOT NULL CHECK (section IN ('exterior', 'interior')),
    note TEXT,
    image_url TEXT,
    sort_order INT NOT NULL DEFAULT 0,
    options JSONB NOT NULL DEFAULT '[]'::jsonb,
    created_at TIMESTAMPTZ DEFAULT now(),
    updated_at TIMESTAMPTZ DEFAULT now()
);

-- 2. Spec Categories
CREATE TABLE IF NOT EXISTS spec_categories (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    icon TEXT NOT NULL,
    sort_order INT NOT NULL DEFAULT 0,
    items JSONB NOT NULL DEFAULT '[]'::jsonb,
    created_at TIMESTAMPTZ DEFAULT now(),
    updated_at TIMESTAMPTZ DEFAULT now()
);

-- 3. Spec Range Tiers
CREATE TABLE IF NOT EXISTS spec_range_tiers (
    tier TEXT PRIMARY KEY,
    hero_image_url TEXT NOT NULL,
    summary TEXT NOT NULL,
    highlights JSONB NOT NULL DEFAULT '[]'::jsonb,
    room_images JSONB NOT NULL DEFAULT '[]'::jsonb,
    created_at TIMESTAMPTZ DEFAULT now(),
    updated_at TIMESTAMPTZ DEFAULT now()
);

-- 4. HomeFast Schemes
CREATE TABLE IF NOT EXISTS homefast_schemes (
    id TEXT PRIMARY KEY,
    name TEXT NOT NULL,
    subtitle TEXT NOT NULL,
    preview_colors JSONB NOT NULL DEFAULT '[]'::jsonb,
    selections JSONB NOT NULL DEFAULT '{}'::jsonb,
    room_images JSONB NOT NULL DEFAULT '[]'::jsonb,
    sort_order INT NOT NULL DEFAULT 0,
    created_at TIMESTAMPTZ DEFAULT now(),
    updated_at TIMESTAMPTZ DEFAULT now()
);

-- 5. Spec-to-Colour Mapping
CREATE TABLE IF NOT EXISTS spec_to_colour_mapping (
    spec_item_id TEXT PRIMARY KEY,
    colour_category_ids TEXT[] NOT NULL DEFAULT '{}',
    created_at TIMESTAMPTZ DEFAULT now()
);

-- 6. Spec Item Images
CREATE TABLE IF NOT EXISTS spec_item_images (
    spec_item_id TEXT PRIMARY KEY,
    base_image_url TEXT,
    tier_images JSONB DEFAULT '{}'::jsonb,
    created_at TIMESTAMPTZ DEFAULT now(),
    updated_at TIMESTAMPTZ DEFAULT now()
);

-- ============================================================
-- Row Level Security — public read, authenticated write
-- ============================================================

ALTER TABLE colour_categories ENABLE ROW LEVEL SECURITY;
ALTER TABLE spec_categories ENABLE ROW LEVEL SECURITY;
ALTER TABLE spec_range_tiers ENABLE ROW LEVEL SECURITY;
ALTER TABLE homefast_schemes ENABLE ROW LEVEL SECURITY;
ALTER TABLE spec_to_colour_mapping ENABLE ROW LEVEL SECURITY;
ALTER TABLE spec_item_images ENABLE ROW LEVEL SECURITY;

-- Public read
CREATE POLICY "Public read colour_categories" ON colour_categories FOR SELECT USING (true);
CREATE POLICY "Public read spec_categories" ON spec_categories FOR SELECT USING (true);
CREATE POLICY "Public read spec_range_tiers" ON spec_range_tiers FOR SELECT USING (true);
CREATE POLICY "Public read homefast_schemes" ON homefast_schemes FOR SELECT USING (true);
CREATE POLICY "Public read spec_to_colour_mapping" ON spec_to_colour_mapping FOR SELECT USING (true);
CREATE POLICY "Public read spec_item_images" ON spec_item_images FOR SELECT USING (true);

-- Authenticated write (for admin management)
CREATE POLICY "Auth write colour_categories" ON colour_categories FOR ALL USING (auth.role() = 'authenticated') WITH CHECK (auth.role() = 'authenticated');
CREATE POLICY "Auth write spec_categories" ON spec_categories FOR ALL USING (auth.role() = 'authenticated') WITH CHECK (auth.role() = 'authenticated');
CREATE POLICY "Auth write spec_range_tiers" ON spec_range_tiers FOR ALL USING (auth.role() = 'authenticated') WITH CHECK (auth.role() = 'authenticated');
CREATE POLICY "Auth write homefast_schemes" ON homefast_schemes FOR ALL USING (auth.role() = 'authenticated') WITH CHECK (auth.role() = 'authenticated');
CREATE POLICY "Auth write spec_to_colour_mapping" ON spec_to_colour_mapping FOR ALL USING (auth.role() = 'authenticated') WITH CHECK (auth.role() = 'authenticated');
CREATE POLICY "Auth write spec_item_images" ON spec_item_images FOR ALL USING (auth.role() = 'authenticated') WITH CHECK (auth.role() = 'authenticated');

