INSERT INTO spec_range_tiers (tier, hero_image_url, summary, highlights, room_images) VALUES
('volos',
 'https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/2m8uxjn7nelckolf349xo.jpg',
 'Everything you need to move into a beautifully finished home. The Volos range delivers quality fixtures, fittings and finishes that meet the high standards AVIA is known for. Designed for smart living, Volos provides a solid foundation of premium essentials without compromising on style or durability.',
 '[{"icon":"countertop.fill","title":"Laminate Benchtops","subtitle":"Quality laminate kitchen benchtops from our standard range"},{"icon":"square.stack.3d.up.fill","title":"Vinyl Plank Flooring","subtitle":"Durable vinyl plank flooring to all living areas"},{"icon":"oven.fill","title":"600mm Appliance Suite","subtitle":"600mm oven, ceramic cooktop & rangehood included"},{"icon":"ruler.fill","title":"2,440mm Ceilings","subtitle":"Standard ceiling height throughout the home"},{"icon":"window.vertical.open","title":"Aluminium Windows","subtitle":"Aluminium windows with keyed locks as standard"},{"icon":"lightbulb.fill","title":"LED Downlights","subtitle":"Standard LED downlights throughout the home"}]',
 '[{"name":"Kitchen","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/2m8uxjn7nelckolf349xo.jpg"},{"name":"Living Room","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/sxfdai5efw1uz7s7qqgmo.jpeg"},{"name":"Bathroom","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/mddj1kprc8nfc5ujxb9sc.jpeg"},{"name":"Bedroom","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/tfj102uo1tuzrdd0hlm6b.jpeg"},{"name":"Alfresco","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/t8j7r8vibjqzvubxzcnbg.jpeg"}]'),
('messina',
 'https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/sxfdai5efw1uz7s7qqgmo.jpeg',
 'Step up to stone benchtops, upgraded tapware and enhanced finishes throughout. The Messina range is our most popular specification, offering the perfect balance of luxury and value. Every detail has been carefully curated to elevate your everyday living experience.',
 '[{"icon":"countertop.fill","title":"20mm Stone Benchtops","subtitle":"Beautiful stone kitchen benchtops from our standard range"},{"icon":"flame.fill","title":"900mm Gas Cooktop","subtitle":"900mm oven with 5-burner gas cooktop & rangehood"},{"icon":"square.stack.3d.up.fill","title":"Hybrid Vinyl Plank","subtitle":"Premium hybrid vinyl plank flooring to living areas"},{"icon":"cabinet.fill","title":"Two-Tone Cabinetry","subtitle":"Soft-close two-tone cabinetry throughout the kitchen"},{"icon":"shower.fill","title":"Semi-Frameless Showers","subtitle":"Semi-frameless shower screens in all wet areas"},{"icon":"ruler.fill","title":"2,590mm Ceilings","subtitle":"Higher ceilings for a more spacious feel"}]',
 '[{"name":"Kitchen","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/sxfdai5efw1uz7s7qqgmo.jpeg"},{"name":"Living Room","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/j4n8xaj2jlxo0wjxvkhr8.jpeg"},{"name":"Bathroom","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/tfj102uo1tuzrdd0hlm6b.jpeg"},{"name":"Bedroom","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/t8j7r8vibjqzvubxzcnbg.jpeg"},{"name":"Alfresco","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/mddj1kprc8nfc5ujxb9sc.jpeg"}]'),
('portobello',
 'https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/j4n8xaj2jlxo0wjxvkhr8.jpeg',
 'The ultimate in home finishes. The Portobello range features designer selections, high-end materials and bespoke details that transform your home into a true showpiece. From premium stone benchtops to matte black fixtures and frameless glass, every element has been chosen to create an unforgettable living experience.',
 '[{"icon":"countertop.fill","title":"Premium Stone Benchtops","subtitle":"20mm premium stone benchtops from our extended range"},{"icon":"flame.fill","title":"Pyrolytic Oven & Induction","subtitle":"900mm pyrolytic oven, induction cooktop, integrated rangehood & dishwasher"},{"icon":"drop.fill","title":"Matte Black Fixtures","subtitle":"Designer matte black tapware & fixtures throughout"},{"icon":"rectangle.portrait.fill","title":"Frameless Glass Showers","subtitle":"Premium frameless glass shower screens"},{"icon":"square.stack.3d.up.fill","title":"Premium Hybrid Flooring","subtitle":"Luxury hybrid flooring from extended range"},{"icon":"ruler.fill","title":"2,740mm Ceilings","subtitle":"Extra-high ceilings for grand proportions"}]',
 '[{"name":"Kitchen","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/j4n8xaj2jlxo0wjxvkhr8.jpeg"},{"name":"Living Room","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/tfj102uo1tuzrdd0hlm6b.jpeg"},{"name":"Bathroom","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/mddj1kprc8nfc5ujxb9sc.jpeg"},{"name":"Bedroom","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/2m8uxjn7nelckolf349xo.jpg"},{"name":"Alfresco","image_url":"https://pub-e001eb4506b145aa938b5d3badbff6a5.r2.dev/attachments/t8j7r8vibjqzvubxzcnbg.jpeg"}]')
